#include <stdio.h>
#include <limits.h>

#define V 5
#define INF INT_MAX

void dijkstra(int graph[V][V], int src) {
    int dist[V];
    int visited[V];
    int predecessor[V];

    // Initialization
    for (int i = 0; i < V; i++) {
        dist[i] = INF;
        visited[i] = 0;
        predecessor[i] = -1;
    }

    dist[src] = 0;

    // Find shortest path for all vertices
    for (int count = 0; count < V - 1; count++) {
        // Pick minimum distance vertex from unvisited
        int u = -1;
        int min = INF;
        for (int v = 0; v < V; v++) {
            if (!visited[v] && dist[v] < min) {
                min = dist[v];
                u = v;
            }
        }

        if (u == -1) break; // Remaining vertices unreachable
        visited[u] = 1;

        // Update distances of adjacent vertices
        for (int v = 0; v < V; v++) {
            if (!visited[v] && graph[u][v] && dist[u] != INF &&
                dist[u] + graph[u][v] < dist[v]) {
                dist[v] = dist[u] + graph[u][v];
                predecessor[v] = u;
            }
        }
    }

    // Print results
    printf("Vertex\tDistance\tPath\n");
    for (int i = 0; i < V; i++) {
        printf("%d\t%d\t\t", i, dist[i]);
        // Backtrack path (not shown for brevity)
        printf("\n");
    }
}

int main() {
    int graph[V][V] = {{0, 4, 2, 0, 0},
                      {0, 0, 1, 5, 0},
                      {0, 0, 0, 8, 10},
                      {0, 0, 0, 0, 2},
                      {0, 0, 0, 0, 0}};
    dijkstra(graph, 0);
    return 0;
}

import java.util.*;

public class Dijkstra {
    static class Edge {
        int to;
        int weight;
        Edge(int to, int weight) {
            this.to = to;
            this.weight = weight;
        }
    }

    static class Node implements Comparable<Node> {
        int vertex;
        int distance;
        Node(int vertex, int distance) {
            this.vertex = vertex;
            this.distance = distance;
        }
        @Override
        public int compareTo(Node other) {
            return Integer.compare(this.distance, other.distance);
        }
    }

    public static int[] dijkstra(List<List<Edge>> graph, int source) {
        int n = graph.size();
        int[] dist = new int[n];
        Arrays.fill(dist, Integer.MAX_VALUE);
        dist[source] = 0;

        PriorityQueue<Node> pq = new PriorityQueue<>();
        pq.add(new Node(source, 0));

        while (!pq.isEmpty()) {
            Node current = pq.poll();
            int u = current.vertex;

            // Skip if we've already found a better path
            if (current.distance > dist[u]) {
                continue;
            }

            // Relax edges
            for (Edge edge : graph.get(u)) {
                int v = edge.to;
                int newDist = dist[u] + edge.weight;

                if (newDist < dist[v]) {
                    dist[v] = newDist;
                    pq.add(new Node(v, newDist));
                }
            }
        }
        return dist;
    }

    public static void main(String[] args) {
        int n = 5;
        List<List<Edge>> graph = new ArrayList<>(n);
        for (int i = 0; i < n; i++) {
            graph.add(new ArrayList<>());
        }

        // Add edges: (u, v, weight)
        graph.get(0).add(new Edge(1, 4));
        graph.get(0).add(new Edge(2, 2));
        graph.get(1).add(new Edge(2, 1));
        graph.get(1).add(new Edge(3, 5));
        graph.get(2).add(new Edge(3, 8));
        graph.get(2).add(new Edge(4, 10));
        graph.get(3).add(new Edge(4, 2));

        int[] dist = dijkstra(graph, 0);
        System.out.println("Shortest distances from source 0:");
        for (int i = 0; i < n; i++) {
            System.out.println("To " + i + ": " + dist[i]);
        }
    }
}
